class Solution:
    def doesValidArrayExist(self, derived: List[int]) -> bool:
        n = len(derived)
        original = [0] * n
        original[0] = 0
        for i in range(n - 1):
            original[i + 1] = original[i] ^ derived[i]
        return original[0] ^ original[-1] == derived[-1]
